function n(){if(typeof window>"u")return null;try{const t=localStorage.getItem("smarter-poker-auth");if(t){const e=JSON.parse(t);if(e!=null&&e.user)return e.user}const r=Object.keys(localStorage).filter(e=>e.startsWith("sb-")&&e.endsWith("-auth-token"));if(r.length>0){const e=JSON.parse(localStorage.getItem(r[0])||"{}");if(e!=null&&e.user)return e.user}const s=localStorage.getItem("sp-cached-header-user");if(s){const e=JSON.parse(s);if(e!=null&&e.id)return e}return null}catch(t){return console.warn("⚠️ [DiamondAuth] LocalStorage parsing failed:",t),null}}export{n as getAuthUser};
